import React, { useState, useEffect, useRef } from 'react';
import { Brain, Sparkles, Activity, MessageSquare, Type, Languages, RefreshCw, Zap, CloudDownload } from 'lucide-react';
import { Translation } from '../utils/i18n/types';
import { Modal } from './ui/Modal';

interface AiPlaygroundModalProps {
  onClose: () => void;
  t: Translation['aiPlayground'];
}

type TaskType = 'sentiment' | 'generation' | 'translation';

const MODELS = {
    sentiment: { id: 'sentiment-analysis', model: 'Xenova/distilbert-base-uncased-finetuned-sst-2-english', size: '~60MB' },
    generation: { id: 'text-generation', model: 'Xenova/distilgpt2', size: '~300MB' },
    translation: { id: 'translation', model: 'Xenova/t5-small', size: '~240MB' }
};

export const AiPlaygroundModal: React.FC<AiPlaygroundModalProps> = ({ onClose, t }) => {
  const [activeTask, setActiveTask] = useState<TaskType>('sentiment');
  const [inputText, setInputText] = useState('');

  // Model State
  const [modelStatus, setModelStatus] = useState<'idle' | 'loading' | 'ready'>('idle');
  const [progress, setProgress] = useState<{status: string, progress?: number, file?: string} | null>(null);

  // Result State
  const [result, setResult] = useState<any /* eslint-disable-line @typescript-eslint/no-explicit-any */>(null);
  const [metrics, setMetrics] = useState<{ loadTime?: string, inferenceTime?: string, device?: string }>({});
  const [isComputing, setIsComputing] = useState(false);

  // Refs
  const pipelineRef = useRef<any /* eslint-disable-line @typescript-eslint/no-explicit-any */>(null);
  const loadedTaskRef = useRef<TaskType | null>(null);

  // Load Model Logic
  const loadModel = async (task: TaskType) => {
      if (loadedTaskRef.current === task && pipelineRef.current) {
          setModelStatus('ready');
          return; // Already loaded
      }

      setModelStatus('loading');
      setResult(null);
      setMetrics({});

      const startTime = performance.now();

      try {

          const { pipeline, env } = await import('@xenova/transformers');

          env.allowLocalModels = false;
          env.useBrowserCache = true;

          const config = MODELS[task];
          // Explicit cast to avoid type mismatch with specific string literals expected by the library
          const pipe = await pipeline(config.id as any /* eslint-disable-line @typescript-eslint/no-explicit-any */, config.model, {
              progress_callback: (data: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) => {
                  if (data.status === 'progress' || data.status === 'initiate') {
                      setProgress(data);
                  }
              }
          });

          pipelineRef.current = pipe;
          loadedTaskRef.current = task;

          const endTime = performance.now();
          setMetrics(prev => ({ ...prev, loadTime: ((endTime - startTime) / 1000).toFixed(2) + 's' }));
          setModelStatus('ready');
          setProgress(null);

      } catch (e: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) {
          console.error("Model load failed", e);
          setProgress({ status: 'error' });
          setModelStatus('idle');
      }
  };

  // Switch Task Effect - NO LONGER AUTO DOWNLOADS
  useEffect(() => {
      // Check if we already have this task loaded
      if (loadedTaskRef.current === activeTask && pipelineRef.current) {
          setModelStatus('ready');
      } else {
          setModelStatus('idle');
      }

      setResult(null);
      setMetrics({});
      setProgress(null);
  }, [activeTask]);

  const handleLoadClick = () => {
      loadModel(activeTask);
  };

  const runInference = async () => {
      if (!pipelineRef.current || !inputText.trim() || isComputing) return;

      setIsComputing(true);
      setResult(null);

      try {
          const start = performance.now();
          let output;

          if (activeTask === 'sentiment') {
              output = await pipelineRef.current(inputText);
          } else if (activeTask === 'generation') {
              output = await pipelineRef.current(inputText, {
                  max_new_tokens: 50,
                  temperature: 0.7
              });
          } else if (activeTask === 'translation') {
              // T5 specific: prefix needed for task
              // Default to English -> German for demo if not specified
              const text = `translate English to German: ${inputText}`;
              output = await pipelineRef.current(text);
          }

          const end = performance.now();

          setResult(output);
          setMetrics(prev => ({ ...prev, inferenceTime: (end - start).toFixed(2) + ' ms' }));
      } catch (e: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) {
          console.error(e);
      }
      setIsComputing(false);
  };

  // UI Helpers
  const getTaskIcon = (task: TaskType) => {
      switch(task) {
          case 'sentiment': return <MessageSquare size={18} />;
          case 'generation': return <Type size={18} />;
          case 'translation': return <Languages size={18} />;
      }
  };

  // Safe translation access
  const getTaskTitle = (task: TaskType) => {

      return t.tasks?.[task]?.title || task;
  };
  const getTaskDesc = (task: TaskType) => {

      return t.tasks?.[task]?.desc || '';
  };
  const getTaskInputPlaceholder = (task: TaskType) => {

      return t.tasks?.[task]?.input || '';
  };
  const getTaskBtnText = (task: TaskType) => {

      return t.tasks?.[task]?.btn || 'Run';
  };

  const getCurrentModelSize = () => {
      return MODELS[activeTask].size;
  };

  return (
    <Modal
        title={t.title}
        icon={<Brain size={24} />}
        onClose={onClose}
        size="4xl"
        fullHeight
        noPadding
    >
        <div className="flex flex-col md:flex-row h-full bg-slate-50 dark:bg-slate-900">

            {/* Sidebar / Tabs */}
            <div className="md:w-64 bg-white dark:bg-slate-800 border-r border-slate-200 dark:border-slate-700 flex flex-col shrink-0">
                <div className="p-4 border-b border-slate-200 dark:border-slate-700">
                    <div className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">{t.select_task || 'Select Model Task'}</div>
                    <div className="flex flex-col gap-2">
                        {(['sentiment', 'generation', 'translation'] as TaskType[]).map(task => (
                            <button
                                key={task}
                                onClick={() => setActiveTask(task)}
                                disabled={isComputing || modelStatus === 'loading'}
                                className={`flex items-center gap-3 p-3 rounded-lg text-left transition-all ${
                                    activeTask === task 
                                    ? 'bg-indigo-50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300 border border-indigo-200 dark:border-indigo-800 shadow-sm' 
                                    : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-700/50'
                                } ${isComputing || modelStatus === 'loading' ? 'opacity-50 cursor-not-allowed' : ''}`}
                            >
                                <div className={`p-2 rounded-md ${activeTask === task ? 'bg-white dark:bg-indigo-900/50' : 'bg-slate-100 dark:bg-slate-700'}`}>
                                    {getTaskIcon(task)}
                                </div>
                                <div>
                                    <div className="text-sm font-bold">{getTaskTitle(task)}</div>
                                </div>
                            </button>
                        ))}
                    </div>
                </div>

                {/* Stats Panel */}
                <div className="mt-auto p-4 bg-slate-50 dark:bg-slate-900/50">
                    <div className="text-[10px] font-bold text-slate-400 uppercase tracking-wider mb-3">{t.perf_metrics || 'Performance Metrics'}</div>
                    <div className="space-y-3">
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-slate-500">{t.metrics?.time_load}</span>
                            <span className="text-xs font-mono font-bold text-slate-700 dark:text-slate-200">{metrics.loadTime || '--'}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-slate-500">{t.metrics?.time_inference}</span>
                            <span className="text-xs font-mono font-bold text-emerald-600 dark:text-emerald-400">{metrics.inferenceTime || '--'}</span>
                        </div>
                        <div className="flex justify-between items-center">
                            <span className="text-xs text-slate-500">{t.metrics?.device}</span>
                            <span className="text-[10px] font-bold px-1.5 py-0.5 bg-slate-200 dark:bg-slate-700 rounded text-slate-600 dark:text-slate-300">WASM / CPU</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Main Content */}
            <div className="flex-1 flex flex-col overflow-hidden">
                {/* Header */}
                <div className="p-6 border-b border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 shrink-0">
                    <div className="flex justify-between items-start">
                        <div>
                            <h2 className="text-xl font-bold text-slate-800 dark:text-white flex items-center gap-2">
                                {getTaskTitle(activeTask)}
                                {modelStatus === 'loading' && <RefreshCw size={16} className="animate-spin text-indigo-500" />}
                            </h2>
                            <p className="text-sm text-slate-500 dark:text-slate-400 mt-1">{getTaskDesc(activeTask)}</p>
                        </div>
                        <div className={`px-3 py-1 rounded-full text-xs font-bold border flex items-center gap-2 ${
                            modelStatus === 'ready' 
                            ? 'bg-emerald-50 text-emerald-700 border-emerald-200 dark:bg-emerald-900/20 dark:text-emerald-400 dark:border-emerald-800' 
                            : modelStatus === 'loading'
                                ? 'bg-amber-50 text-amber-700 border-amber-200 dark:bg-amber-900/20 dark:text-amber-400 dark:border-amber-800'
                                : 'bg-slate-100 text-slate-500 border-slate-200 dark:bg-slate-800 dark:text-slate-400 dark:border-slate-700'
                        }`}>
                            <div className={`w-2 h-2 rounded-full ${modelStatus === 'ready' ? 'bg-emerald-500' : modelStatus === 'loading' ? 'bg-amber-500 animate-pulse' : 'bg-slate-400'}`}></div>
                            {modelStatus === 'ready' ? t.status?.ready : modelStatus === 'loading' ? t.status?.loading_model : t.status?.idle}
                        </div>
                    </div>

                    {/* Progress Bar */}
                    {modelStatus === 'loading' && (
                        <div className="mt-4">
                            <div className="flex justify-between text-xs text-slate-500 mb-1">
                                <span>Downloading Weights...</span>
                                <span>{progress?.progress ? Math.round(progress.progress) : 0}%</span>
                            </div>
                            <div className="h-1.5 w-full bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                                <div 
                                    className="h-full bg-indigo-500 transition-all duration-200" 
                                    style={{ width: `${progress?.progress || 5}%` }}
                                />
                            </div>
                            {progress?.file && <div className="text-[10px] text-slate-400 mt-1 font-mono truncate">{progress.file}</div>}
                        </div>
                    )}
                </div>

                {/* Interaction Area */}
                <div className="flex-1 p-6 overflow-y-auto bg-slate-50 dark:bg-slate-900/50 flex flex-col">

                    <div className="w-full max-w-3xl mx-auto space-y-6">
                        {/* Input */}
                        <div className="space-y-2">
                            <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">Input</label>
                            <div className="relative group">
                                <textarea 
                                    value={inputText}
                                    onChange={(e) => setInputText(e.target.value)}
                                    placeholder={modelStatus === 'ready' ? getTaskInputPlaceholder(activeTask) : ""}
                                    className={`w-full p-4 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl focus:ring-2 focus:ring-indigo-500/50 focus:border-indigo-500 outline-none resize-none h-32 text-sm text-slate-800 dark:text-slate-200 shadow-sm transition-shadow ${modelStatus !== 'ready' ? 'opacity-50 cursor-not-allowed select-none' : ''}`}
                                    disabled={modelStatus !== 'ready' || isComputing}
                                />

                                {/* Overlay for Idle State - Manual Load Trigger */}
                                {modelStatus === 'idle' && (
                                    <div className="absolute inset-0 flex items-center justify-center z-10">
                                        <button 
                                            onClick={handleLoadClick}
                                            className="px-6 py-3 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/20 active:scale-95 transition-all flex items-center gap-2 font-bold"
                                        >
                                            <CloudDownload size={20} />
                                            {t.btn_load} ({getCurrentModelSize()})
                                        </button>
                                    </div>
                                )}

                                {/* Main Action Button (Only visible if model is ready or loading) */}
                                {modelStatus !== 'idle' && (
                                    <button 
                                        onClick={runInference}
                                        disabled={modelStatus !== 'ready' || isComputing || !inputText}
                                        className={`absolute bottom-3 right-3 px-4 py-2 rounded-lg font-bold text-white shadow-lg flex items-center gap-2 transition-all active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed ${
                                            isComputing ? 'bg-slate-400 cursor-wait' : 'bg-indigo-600 hover:bg-indigo-700'
                                        }`}
                                    >
                                        {isComputing ? <Activity className="animate-spin" size={16} /> : <Zap size={16} fill="currentColor" />}
                                        {isComputing ? t.status?.computing : getTaskBtnText(activeTask)}
                                    </button>
                                )}
                            </div>
                        </div>

                        {/* Output */}
                        {result && (
                            <div className="space-y-2 animate-in fade-in slide-in-from-bottom-4 duration-500">
                                <label className="text-xs font-bold text-slate-500 uppercase tracking-wider">{t.result_label}</label>
                                <div className="bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-xl p-6 shadow-sm relative overflow-hidden">
                                    <div className="absolute top-0 left-0 w-1 h-full bg-gradient-to-b from-indigo-500 to-purple-500"></div>

                                    {activeTask === 'sentiment' && (
                                        <div className="flex items-center gap-4">
                                            <div className={`p-3 rounded-full ${result[0].label === 'POSITIVE' ? 'bg-emerald-100 text-emerald-600' : 'bg-red-100 text-red-600'}`}>
                                                <Sparkles size={24} />
                                            </div>
                                            <div>
                                                <div className="text-2xl font-bold text-slate-800 dark:text-white">{result[0].label}</div>
                                                <div className="text-sm text-slate-500">
                                                    {t.confidence}: <span className="font-mono font-bold text-indigo-600 dark:text-indigo-400">{(result[0].score * 100).toFixed(2)}%</span>
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {(activeTask === 'generation' || activeTask === 'translation') && (
                                        <div>
                                            <p className="text-base text-slate-700 dark:text-slate-200 leading-relaxed whitespace-pre-wrap font-serif">
                                                {activeTask === 'generation' ? result[0].generated_text : result[0].translation_text}
                                            </p>
                                        </div>
                                    )}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    </Modal>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Mic, Square, Download, Play, Pause, RefreshCw, Activity } from 'lucide-react';
import { Translation } from '../utils/i18n/types';
import { Modal } from './ui/Modal';

interface AudioRecorderModalProps {
  onClose: () => void;
  t: Translation['audioTool'];
}

export const AudioRecorderModal: React.FC<AudioRecorderModalProps> = ({ onClose, t }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const audioContextRef = useRef<AudioContext | null>(null);
  const analyzerRef = useRef<AnalyserNode | null>(null);
  const dataArrayRef = useRef<Uint8Array | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const animationRef = useRef<number | null>(null);
  const audioPlayerRef = useRef<HTMLAudioElement | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const isUnmounted = useRef(false);

  const [_stream, setStream] = useState<MediaStream | null>(null);
  const [isRecording, setIsRecording] = useState(false);
  const [_audioBlob, setAudioBlob] = useState<Blob | null>(null);
  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [recordingDuration, setRecordingDuration] = useState(0);
  const [isPlaying, setIsPlaying] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // New info states
  const [fileSize, setFileSize] = useState<string>('');
  const [sampleRate, setSampleRate] = useState<number>(0);
  const [mimeType, setMimeType] = useState<string>('');

  const stopAudioTracks = () => {
      if (streamRef.current) {
          streamRef.current.getTracks().forEach(track => {
              track.stop();
              track.enabled = false;
          });
          streamRef.current = null;
      }
      setStream(null);
  };

  const handleClose = () => {
    stopAudioTracks();
    onClose();
  };

  useEffect(() => {
     isUnmounted.current = false;
     return () => {
         isUnmounted.current = true;
         stopAudioTracks();
     };
  }, []);

  // Timer for duration
  useEffect(() => {
    let interval: number;
    if (isRecording) {
      interval = window.setInterval(() => {
        setRecordingDuration(d => d + 1);
      }, 1000);
    }
    return () => clearInterval(interval);
  }, [isRecording]);

  // Audio Playback Listener
  useEffect(() => {
      const player = audioPlayerRef.current;
      if (player) {
          const onEnded = () => setIsPlaying(false);
          const onPause = () => setIsPlaying(false);
          const onPlay = () => setIsPlaying(true);

          player.addEventListener('ended', onEnded);
          player.addEventListener('pause', onPause);
          player.addEventListener('play', onPlay);

          return () => {
              player.removeEventListener('ended', onEnded);
              player.removeEventListener('pause', onPause);
              player.removeEventListener('play', onPlay);
          }
      }
  }, [audioUrl]);

  // Visualizer Loop
  const isVisualizerActiveRef = useRef(false);

  const drawVisualizer = () => {
    if (!canvasRef.current || !analyzerRef.current || !dataArrayRef.current) return;

    if (isUnmounted.current || !isVisualizerActiveRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    const analyzer = analyzerRef.current;
    const dataArray = dataArrayRef.current;

    if (!ctx) return;

    const bufferLength = analyzer.frequencyBinCount;
    analyzer.getByteFrequencyData(dataArray);

    ctx.fillStyle = 'rgb(248, 250, 252)'; // slate-50 (This needs to be dynamic or transparent for dark mode)
    // Dark mode bg check (simple heuristic or use transparent clear)
    const isDark = document.documentElement.classList.contains('dark');
    if(isDark) ctx.fillStyle = 'rgb(15, 23, 42)'; // slate-900

    ctx.clearRect(0, 0, canvas.width, canvas.height); 

    const barWidth = (canvas.width / bufferLength) * 2.5;
    let barHeight;
    let x = 0;

    for (let i = 0; i < bufferLength; i++) {
        barHeight = (dataArray[i] / 255) * canvas.height;

        // Gradient color based on height
        const hue = 220 + (barHeight / canvas.height) * 40; // Blue/Indigo range
        ctx.fillStyle = `hsl(${hue}, 80%, 60%)`;

        ctx.fillRect(x, canvas.height - barHeight, barWidth, barHeight);

        x += barWidth + 1;
    }

    // Schedule next frame
    animationRef.current = requestAnimationFrame(drawVisualizer);
  };

  // Start visualizer only when recording or playing
  useEffect(() => {
      isVisualizerActiveRef.current = isRecording || isPlaying;
      if (isRecording || isPlaying) {
          if (audioContextRef.current && audioContextRef.current.state === 'suspended') {
              audioContextRef.current.resume();
          }
          if (animationRef.current) cancelAnimationFrame(animationRef.current);
          drawVisualizer();
      } else {
          if (animationRef.current) {
              cancelAnimationFrame(animationRef.current);
          }
      }

      return () => {
          if (animationRef.current) {
              cancelAnimationFrame(animationRef.current);
          }
      }
  }, [isRecording, isPlaying]);

  // Audio Playback Node setup
  useEffect(() => {
      if (audioUrl && audioPlayerRef.current && audioContextRef.current && analyzerRef.current) {
          // Check to prevent creating MediaElementSource twice on the same element
          if (!(audioPlayerRef.current as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).hasSourceConnected) {
              const audioCtx = audioContextRef.current;
              // Add a new track source
              const source = audioCtx.createMediaElementSource(audioPlayerRef.current);
              source.connect(analyzerRef.current);
              // Important: We MUST connect it to destination to hear it, but we only create ONE analyzer!
              // For microphone record, we didn't connect analyzer to destination.
              // To hear playback, we can connect the element source straight to destination as well.
              source.connect(audioCtx.destination);
              (audioPlayerRef.current as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).hasSourceConnected = true;
          }
      }
  }, [audioUrl]);

  // Component cleanup
  useEffect(() => {
     let isAudioContextCleaned = false;

     return () => {
         if (animationRef.current) cancelAnimationFrame(animationRef.current);

         // Stop recording if active
         if (mediaRecorderRef.current && mediaRecorderRef.current.state !== 'inactive') {
            mediaRecorderRef.current.stop();
         }

         // Disconnect nodes
         if (sourceRef.current) sourceRef.current.disconnect();
         if (audioContextRef.current && !isAudioContextCleaned) {
             isAudioContextCleaned = true;
             if (audioContextRef.current.state !== 'closed') {
                audioContextRef.current.close().catch(console.error);
             }
         }

         // Stop all tracks to release microphone hardware
         stopAudioTracks();
     };
  }, []);

  const initAudioAndRecord = async () => {
    try {
      let localStream = streamRef.current;

      if (!localStream) {
          localStream = await navigator.mediaDevices.getUserMedia({ audio: true });
          if (isUnmounted.current) {
              localStream.getTracks().forEach(track => track.stop());
              return;
          }
          streamRef.current = localStream;
          setStream(localStream);
      }

      // Setup Audio Context for Visualizer if not already setup
      if (!audioContextRef.current) {
          const AudioContext = window.AudioContext || (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).webkitAudioContext;
          const audioCtx = new AudioContext();
          setSampleRate(audioCtx.sampleRate);

          const analyzer = audioCtx.createAnalyser();
          const source = audioCtx.createMediaStreamSource(localStream);

          analyzer.fftSize = 2048;
          const bufferLength = analyzer.frequencyBinCount;
          const dataArray = new Uint8Array(bufferLength);

          source.connect(analyzer);

          audioContextRef.current = audioCtx;
          analyzerRef.current = analyzer;
          dataArrayRef.current = dataArray;
          sourceRef.current = source;
      }

      // Try to start recording right away
      try {
          const recorder = new MediaRecorder(localStream);
          setMimeType(recorder.mimeType);
          const chunks: Blob[] = [];

          recorder.ondataavailable = (e) => {
              if (e.data.size > 0) chunks.push(e.data);
          };

          recorder.onstop = () => {
              // Create blob with actual mime type from recorder
              const blob = new Blob(chunks, { type: recorder.mimeType || 'audio/webm' });
              setAudioBlob(blob);
              setAudioUrl(URL.createObjectURL(blob));

              const sizeInKB = blob.size / 1024;
              setFileSize(sizeInKB > 1024 ? `${(sizeInKB / 1024).toFixed(2)} MB` : `${sizeInKB.toFixed(2)} KB`);
          };

          recorder.start();
          mediaRecorderRef.current = recorder;
          setIsRecording(true);
          setRecordingDuration(0);
          setAudioBlob(null);
          setAudioUrl(null);

      } catch (e: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) {
          console.error("Recorder error:", e);
      }

    } catch (err: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) {
      console.error("Error accessing microphone:", err);
      setError(t.error_mic);
    }
  };

  const startRecording = () => {
    initAudioAndRecord();
  };

  const stopRecording = () => {
      if (mediaRecorderRef.current && isRecording) {
          mediaRecorderRef.current.stop();
          setIsRecording(false);

          if (animationRef.current) {
              cancelAnimationFrame(animationRef.current);
          }

          // Optionally release mic directly after stopping
          stopAudioTracks();
      }
  };

  const togglePlayback = () => {
      if (audioPlayerRef.current) {
          if (isPlaying) {
              audioPlayerRef.current.pause();
          } else {
              audioPlayerRef.current.play();
          }
      }
  };

  const downloadAudio = () => {
      if (audioUrl) {
          const link = document.createElement('a');
          link.href = audioUrl;
          // Extract extension from mimeType if possible, default to webm
          const ext = mimeType.includes('mp4') ? 'mp4' : mimeType.includes('ogg') ? 'ogg' : 'webm';
          link.download = `audio-recording-${Date.now()}.${ext}`;
          document.body.appendChild(link);
          link.click();
          document.body.removeChild(link);
      }
  };

  const reset = () => {
      setAudioBlob(null);
      setAudioUrl(null);
      setRecordingDuration(0);
  };

  const formatTime = (seconds: number) => {
      const mins = Math.floor(seconds / 60);
      const secs = seconds % 60;
      return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <Modal
        title={t.title}
        icon={<Mic size={24} />}
        onClose={handleClose}
        size="lg"
    >
        {({ close: _close }) => (
            <>
                {/* Content */}
                <div className="flex flex-col gap-6 items-center">

                    {error ? (
                        <div className="text-red-500 font-medium text-center p-4 bg-red-50 dark:bg-red-900/20 rounded-lg w-full">
                            {error}
                        </div>
                    ) : (
                        <>
                            {/* Visualizer Area */}
                            <div className="w-full h-32 bg-slate-200 dark:bg-slate-900 rounded-xl overflow-hidden relative shadow-inner border border-slate-200 dark:border-slate-700">
                                <canvas ref={canvasRef} width={500} height={128} className="w-full h-full" />

                                {!isRecording && !isPlaying && !audioUrl && (
                                    <div className="absolute inset-0 flex items-center justify-center bg-slate-200 dark:bg-slate-900 z-10">
                                        <span className="text-slate-400 dark:text-slate-500 text-xs font-semibold tracking-wide">
                                            {t.start_record}
                                        </span>
                                    </div>
                                )}

                                {!isRecording && !isPlaying && audioUrl && (
                                    <div className="absolute inset-0 flex items-center justify-center bg-transparent z-10">
                                        <span className="text-slate-400/80 dark:text-slate-500/80 text-xs font-semibold tracking-wide">
                                            {t.listening} {/* Or play text depending on localization */}
                                        </span>
                                    </div>
                                )}

                                {!audioUrl && isRecording && (
                                    <div className="absolute top-2 right-2 flex items-center gap-1.5 px-2 py-1 bg-black/10 dark:bg-white/10 rounded-full z-20">
                                        <Activity size={12} className="text-slate-600 dark:text-slate-300" />
                                        <span className="text-[10px] font-medium text-slate-600 dark:text-slate-300 uppercase tracking-wide">
                                            Recording
                                        </span>
                                    </div>
                                )}
                            </div>

                            {/* Timer */}
                            <div className="font-mono text-4xl font-bold text-slate-700 dark:text-slate-200 tracking-wider">
                                {formatTime(recordingDuration)}
                            </div>

                            {/* Controls */}
                            <div className="flex gap-4 items-center">
                                {!audioUrl ? (
                                    !isRecording ? (
                                        <button 
                                            onClick={startRecording}
                                            className="w-16 h-16 bg-red-500 rounded-full flex items-center justify-center text-white shadow-lg shadow-red-200 dark:shadow-red-900/50 hover:bg-red-600 hover:scale-105 active:scale-95 transition-all"
                                            title={t.start_record}
                                        >
                                            <Mic size={32} />
                                        </button>
                                    ) : (
                                        <button 
                                            onClick={stopRecording}
                                            className="w-16 h-16 bg-slate-800 dark:bg-slate-600 rounded-full flex items-center justify-center text-white shadow-lg hover:bg-slate-900 dark:hover:bg-slate-700 hover:scale-105 active:scale-95 transition-all"
                                            title={t.stop_record}
                                        >
                                            <Square size={28} fill="currentColor" />
                                        </button>
                                    )
                                ) : (
                                    <div className="flex gap-3">
                                        <button 
                                            onClick={reset}
                                            className="w-12 h-12 bg-slate-200 dark:bg-slate-700 rounded-full flex items-center justify-center text-slate-600 dark:text-slate-300 hover:bg-slate-300 dark:hover:bg-slate-600 transition-all"
                                            title="Reset"
                                        >
                                            <RefreshCw size={20} />
                                        </button>

                                        <button 
                                            onClick={togglePlayback}
                                            className="w-16 h-16 bg-indigo-600 rounded-full flex items-center justify-center text-white shadow-lg shadow-indigo-200 dark:shadow-indigo-900/50 hover:bg-indigo-700 hover:scale-105 active:scale-95 transition-all"
                                        >
                                            {isPlaying ? <Pause size={32} fill="currentColor" /> : <Play size={32} fill="currentColor" className="ml-1" />}
                                        </button>

                                        <button 
                                            onClick={downloadAudio}
                                            className="w-12 h-12 bg-emerald-100 dark:bg-emerald-900/30 rounded-full flex items-center justify-center text-emerald-600 dark:text-emerald-400 hover:bg-emerald-200 dark:hover:bg-emerald-900/50 transition-all"
                                            title={t.download}
                                        >
                                            <Download size={20} />
                                        </button>
                                    </div>
                                )}
                            </div>

                            {/* Info Stats (Shows after recording) */}
                            {audioUrl && (
                                <div className="grid grid-cols-3 gap-2 w-full mt-2">
                                    <div className="bg-white dark:bg-slate-800 p-2 rounded-lg border border-slate-200 dark:border-slate-700 text-center">
                                        <div className="text-[10px] text-slate-400 uppercase tracking-wider mb-0.5">{t.details_size}</div>
                                        <div className="font-semibold text-slate-700 dark:text-slate-200 text-sm">{fileSize}</div>
                                    </div>
                                    <div className="bg-white dark:bg-slate-800 p-2 rounded-lg border border-slate-200 dark:border-slate-700 text-center">
                                        <div className="text-[10px] text-slate-400 uppercase tracking-wider mb-0.5">{t.details_rate}</div>
                                        <div className="font-semibold text-slate-700 dark:text-slate-200 text-sm">{sampleRate} Hz</div>
                                    </div>
                                    <div className="bg-white dark:bg-slate-800 p-2 rounded-lg border border-slate-200 dark:border-slate-700 text-center">
                                        <div className="text-[10px] text-slate-400 uppercase tracking-wider mb-0.5">{t.details_type}</div>
                                        <div className="font-semibold text-slate-700 dark:text-slate-200 text-xs break-all pt-1" title={mimeType}>
                                            {mimeType.split(';')[0]}
                                        </div>
                                    </div>
                                </div>
                            )}

                            {/* Hidden Audio Element */}
                            {audioUrl && (
                                <audio ref={audioPlayerRef} src={audioUrl} />
                            )}
                        </>
                    )}

                </div>
            </>
        )}
    </Modal>
  );
};

