                            className={`flex-1 py-1.5 px-2 rounded-md text-xs sm:text-sm font-medium transition-all ${
                                activeTab === 'v4' 
                                ? 'bg-white dark:bg-slate-600 text-indigo-600 dark:text-white shadow-sm' 
