import { Badge } from './ui/Badge';

interface InfoItemProps {
  label: string;
  value: string | number | boolean | null | undefined;
  subValue?: string;
  isFeature?: boolean;
}

// Memoized InfoItem to prevent re-renders of list items
const InfoItem = memo<InfoItemProps>(({ label, value, subValue, isFeature }) => {
  let displayValue: React.ReactNode = value ?? 'N/A';

  if (typeof value === 'boolean') {
    displayValue = value ? (
        <Badge variant="success">Supported</Badge>
    ) : (
        <Badge variant="neutral">Not Supported</Badge>
    );
  } else if (isFeature) {
      // If it's passed as a string but represents a boolean status
      if(value === 'Yes' || value === 'Supported' || value === 'Connected') {
          displayValue = <Badge variant="success">{value}</Badge>;
      } else if(value === 'No' || value === 'Not Supported' || value === 'Offline') {
          displayValue = <Badge variant="neutral">{value}</Badge>;
      } else {
          // Default text style for strings
          displayValue = <span className="text-sm text-slate-800 dark:text-slate-200 break-all">{value}</span>;
      }
  } else {
      // Standard text value
      displayValue = <span className="text-sm text-slate-800 dark:text-slate-200 break-all">{value}</span>;
  }

  return (
    <div className="flex justify-between items-center py-2.5 border-b border-slate-50 dark:border-slate-700/50 last:border-0 hover:bg-slate-50 dark:hover:bg-slate-700/30 transition-colors px-2 -mx-2 rounded">
      <span className="text-sm text-slate-500 dark:text-slate-400 font-medium">{label}</span>
      <div className="text-right">
        {displayValue}
        {subValue && <div className="text-xs text-slate-400 dark:text-slate-500 mt-0.5">{subValue}</div>}
      </div>
    </div>
  );
});

interface InfoCardProps {
