import React, { useState, useRef, useEffect } from 'react';
import { Globe, Play, Square, Activity, ArrowLeft, Zap, LayoutDashboard } from 'lucide-react';
import { Translation } from '../utils/i18n/types';
import { Modal } from './ui/Modal';
import { measureLatency, LATENCY_REGIONS, LatencyResult, LatencyRegion } from '../services/detectors/globalLatency';
import { WorldMap } from './heatmap/WorldMap';
import { TraceGraph } from './heatmap/TraceGraph';


interface NetworkHeatmapModalProps {
  onClose: () => void;
  t: Translation['heatmap'];
}

interface TraceStats {
    count: number;
    lossCount: number;
    min: number;
    max: number;
    avg: number;
    jitter: number;
    last: number | null;
}

export const NetworkHeatmapModal: React.FC<NetworkHeatmapModalProps> = ({ onClose, t }) => {
  // Global Map State
  const [isRunningMap, setIsRunningMap] = useState(false);
  const [results, setResults] = useState<Record<string, LatencyResult>>({});

  // Detail/Trace View State
  const [selectedRegion, setSelectedRegion] = useState<LatencyRegion | null>(null);
  const [traceData, setTraceData] = useState<(number | null)[]>([]); // null = timeout
  const [isRunningTrace, setIsRunningTrace] = useState(false);
  const [traceStats, setTraceStats] = useState<TraceStats>({
      count: 0,
      lossCount: 0,
      min: Infinity,
      max: 0,
      avg: 0,
      jitter: 0,
      last: 0
  });

  const abortControllerRef = useRef<AbortController | null>(null);
  const traceIntervalRef = useRef<number | null>(null);

  const handleClose = () => {
      stopTest();
      stopTrace();
      onClose();
  };

  const stopTest = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
      }
      setIsRunningMap(false);
  };

  const stopTrace = () => {
      if (traceIntervalRef.current) {
          window.clearTimeout(traceIntervalRef.current);
          traceIntervalRef.current = null;
      }
      setIsRunningTrace(false);
  };

  // --- Global Map Logic ---
  const runTest = async () => {
      if (isRunningMap) return;
      setIsRunningMap(true);
      setResults({});
      abortControllerRef.current = new AbortController();

      // Batch requests to avoid choking browser
      const batchSize = 3;
      const queue = [...LATENCY_REGIONS];

      while (queue.length > 0 && !abortControllerRef.current.signal.aborted) {
          const batch = queue.splice(0, batchSize);

          // Mark as pending
          setResults(prev => {
              const next = { ...prev };
              batch.forEach(r => next[r.id] = { id: r.id, latency: 0, status: 'pending' });
              return next;
          });

          await Promise.all(batch.map(async (region) => {
              try {
                  const latency = await measureLatency(region.url);
                  setResults(prev => ({
                      ...prev,
                      [region.id]: { id: region.id, latency, status: 'success' }
                  }));
              } catch {
                  setResults(prev => ({
                      ...prev,
                      [region.id]: { id: region.id, latency: 0, status: 'error' }
                  }));
              }
          }));

          // Small delay between batches
          await new Promise(r => setTimeout(r, 200));
      }

      setIsRunningMap(false);
  };

  // --- Trace Logic (Pseudo-MTR) ---
  const startTrace = () => {
      if (isRunningTrace || !selectedRegion) return;

      // Reset stats on start if trace data is empty or if restarting manually
      if (traceData.length === 0 || !isRunningTrace) {
          setTraceData(new Array(60).fill(0).map(() => 0)); 
          setTraceStats({ count: 0, lossCount: 0, min: Infinity, max: 0, avg: 0, jitter: 0, last: 0 });
      }

      setIsRunningTrace(true);

      const region = selectedRegion;

      const loop = async () => {
          const targetUrl = `${region.url}?t=${Date.now()}`;
          const start = performance.now();
          let latency: number | null = null;

          try {
              const controller = new AbortController();
              const timeoutId = setTimeout(() => controller.abort(), 2000);

              await fetch(targetUrl, { 
                  mode: 'no-cors', 
                  cache: 'no-store', 
                  method: 'HEAD',
                  signal: controller.signal
              });
              clearTimeout(timeoutId);
              const end = performance.now();
              latency = Math.round(end - start);
          } catch {
              latency = null; // Timeout or error
          }

          // Update Data & Stats
          setTraceData(prev => [...prev.slice(1), latency]);

          setTraceStats(prev => {
              const newCount = prev.count + 1;
              const isLoss = latency === null;
              const newLossCount = prev.lossCount + (isLoss ? 1 : 0);

              if (isLoss) {
                  return { ...prev, count: newCount, lossCount: newLossCount };
              }

              const val = latency!;
              const newMin = Math.min(prev.min, val);
              const newMax = Math.max(prev.max, val);
              const newAvg = Math.round(prev.avg + (val - prev.avg) / (newCount - newLossCount));
              const newJitter = prev.last ? Math.abs(val - prev.last) : 0;
              const smoothJitter = Math.round(prev.jitter * 0.9 + newJitter * 0.1);

              return {
                  count: newCount,
                  lossCount: newLossCount,
                  min: newMin,
                  max: newMax,
                  avg: newAvg,
                  jitter: smoothJitter,
                  last: val
              };
          });

          if (traceIntervalRef.current) {
              traceIntervalRef.current = window.setTimeout(loop, 500);
          }
      };

      traceIntervalRef.current = window.setTimeout(loop, 0);
  };

  const handleStartTrace = () => {
      startTrace();
  };

  const handleStopTrace = () => {
      stopTrace();
  };

  // Reset when changing regions
  useEffect(() => {
      if (selectedRegion) {
          stopTrace(); 
          setTraceData(new Array(60).fill(0));
          setTraceStats({ count: 0, lossCount: 0, min: Infinity, max: 0, avg: 0, jitter: 0, last: 0 });
      } else {
          stopTrace();
      }
      return () => stopTrace();
  }, [selectedRegion]);


  // Helpers
  const getLatencyColor = (latency: number) => {
      if (latency === 0) return 'text-slate-400';
      if (latency < 100) return 'text-emerald-500';
      if (latency < 200) return 'text-yellow-500';
      return 'text-red-500';
  };

  const getRegionName = (id: string, defaultName: string) => {

      // @ts-expect-error auto-fixed
      return t.regions?.[id] || defaultName;
  };

  const localizedRegions = LATENCY_REGIONS.map(r => ({
      ...r,
      name: getRegionName(r.id, r.name)
  }));

  return (
    <Modal
        title={selectedRegion ? t.mtr_title : t.title}
        icon={selectedRegion ? <Activity size={24} /> : <Globe size={24} />}
        onClose={handleClose}
        size="3xl"
        fullHeight
        noPadding
    >
        {/* Style injection for animations */}
        <style>{`
            @keyframes slideInRight {
                from { opacity: 0; transform: translateX(20px); }
                to { opacity: 1; transform: translateX(0); }
            }
            @keyframes slideInLeft {
                from { opacity: 0; transform: translateX(-20px); }
                to { opacity: 1; transform: translateX(0); }
            }
            .animate-slide-right { animation: slideInRight 0.3s ease-out forwards; }
            .animate-slide-left { animation: slideInLeft 0.3s ease-out forwards; }
        `}</style>

        <div className="flex flex-col h-full bg-slate-50 dark:bg-slate-900 relative overflow-hidden">

            {selectedRegion ? (
                // --- VIEW B: DETAILED TRACE (Full Overlay) ---
                <div className="flex flex-col h-full w-full absolute inset-0 bg-slate-50 dark:bg-slate-900 z-10 animate-slide-right">
                    {/* Header */}
                    <div className="p-4 border-b border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 flex items-center justify-between shadow-sm z-20">
                        <button 
                            onClick={() => setSelectedRegion(null)}
                            className="flex items-center gap-2 px-3 py-1.5 rounded-lg text-sm font-medium text-slate-500 hover:text-slate-800 hover:bg-slate-100 dark:text-slate-400 dark:hover:text-white dark:hover:bg-slate-700 transition-colors"
                        >
                            <ArrowLeft size={16} />
                            {t.back}
                        </button>
                        <div className="flex items-center gap-3">
                            <span className="text-lg font-bold text-slate-800 dark:text-white">
                                {getRegionName(selectedRegion.id, selectedRegion.name)}
                            </span>
                            <div className="h-4 w-px bg-slate-300 dark:bg-slate-600 hidden sm:block" />
                            <span className="font-mono text-xs text-slate-400 hidden sm:block">{selectedRegion.url.split('/')[2]}</span>
                        </div>

                        {/* Prominent Controls */}
                        {!isRunningTrace ? (
                            <button 
                                onClick={handleStartTrace}
                                className="px-6 py-2 bg-emerald-600 hover:bg-emerald-700 text-white rounded-lg font-bold shadow-lg shadow-emerald-500/20 active:scale-95 transition-all flex items-center gap-2"
                            >
                                <Play size={16} fill="currentColor" />
                                {t.start}
                            </button>
                        ) : (
                            <button 
                                onClick={handleStopTrace}
                                className="px-6 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg font-bold shadow-lg shadow-red-500/20 active:scale-95 transition-all flex items-center gap-2 animate-pulse"
                            >
                                <Square size={16} fill="currentColor" />
                                {t.stop}
                            </button>
                        )}
                    </div>

                    {/* Main Graph Area */}
                    <div className="flex-1 p-6 bg-slate-900 relative overflow-hidden flex flex-col items-center justify-center min-h-0">
                        <div className={`absolute inset-0 transition-opacity duration-500 ${isRunningTrace ? 'opacity-80' : 'opacity-30 blur-sm'}`}>
                            <TraceGraph data={traceData} height={300} />
                        </div>

                        {/* Overlay for Idle State */}
                        {!isRunningTrace && traceStats.count === 0 && (
                            <div className="absolute inset-0 flex items-center justify-center bg-black/20 z-10">
                                <button 
                                    onClick={handleStartTrace}
                                    className="group relative flex flex-col items-center justify-center w-32 h-32 rounded-full bg-emerald-600/90 text-white shadow-2xl hover:scale-105 hover:bg-emerald-500 transition-all cursor-pointer backdrop-blur-sm border-4 border-white/10"
                                >
                                    <Zap size={40} className="mb-2 fill-white" />
                                    <span className="text-sm font-bold uppercase tracking-widest">{t.start}</span>
                                    <div className="absolute inset-0 rounded-full border-2 border-emerald-400/50 animate-ping pointer-events-none"></div>
                                </button>
                            </div>
                        )}

                        {/* Center Metric (Only show if we have data) */}
                        {traceStats.count > 0 && (
                            <div className="relative z-10 text-center mix-blend-difference">
                                <div className="text-6xl font-black text-white tabular-nums tracking-tighter">
                                    {traceStats.last ?? '--'}
                                </div>
                                <div className="text-sm font-bold text-indigo-400 uppercase tracking-widest mt-1">ms {t.current}</div>
                            </div>
                        )}
                    </div>

                    {/* Stats Grid */}
                    <div className="grid grid-cols-4 border-t border-slate-200 dark:border-slate-700 bg-white dark:bg-slate-800 shrink-0">
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.packet_loss}</div>
                            <div className={`text-xl font-bold tabular-nums ${traceStats.lossCount > 0 ? 'text-red-500' : 'text-emerald-500'}`}>
                                {traceStats.count > 0 ? ((traceStats.lossCount / traceStats.count) * 100).toFixed(1) : 0}%
                            </div>
                        </div>
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.jitter}</div>
                            <div className={`text-xl font-bold tabular-nums ${traceStats.jitter > 10 ? 'text-amber-500' : 'text-slate-700 dark:text-slate-200'}`}>
                                {traceStats.jitter} ms
                            </div>
                        </div>
                        <div className="p-4 border-r border-slate-100 dark:border-slate-700 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.avg_latency}</div>
                            <div className="text-xl font-bold text-slate-700 dark:text-slate-200 tabular-nums">
                                {traceStats.avg} ms
                            </div>
                        </div>
                        <div className="p-4 text-center">
                            <div className="text-[10px] text-slate-400 uppercase font-bold tracking-wider mb-1">{t.samples}</div>
                            <div className="text-xl font-bold text-slate-700 dark:text-slate-200 tabular-nums">
                                {traceStats.count}
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                // --- VIEW A: MAP & LIST (Dashboard Layout) ---
                <div className="flex flex-col lg:flex-row h-full w-full absolute inset-0 bg-slate-50 dark:bg-slate-900 z-0 animate-slide-left">

                    {/* Left/Top: Map Area */}
                    <div className="relative shrink-0 lg:flex-1 bg-slate-100 dark:bg-black/20 flex flex-col justify-center overflow-hidden border-b lg:border-b-0 lg:border-r border-slate-200 dark:border-slate-700 min-h-[300px] lg:min-h-0">
                        <div className="w-full h-full p-6 flex items-center justify-center">
                             {/* Map Container */}
                             <div className="w-full max-w-5xl h-full">
                                <WorldMap 
                                    regions={localizedRegions} 
                                    results={results} 
                                    onRegionSelect={setSelectedRegion} 
                                />
                             </div>
                        </div>

                        {/* Overlay Controls */}
                        <div className="absolute bottom-6 left-0 right-0 flex justify-center pointer-events-none z-10">
                             <button 
                                onClick={isRunningMap ? stopTest : runTest}
                                className={`
                                    pointer-events-auto px-8 py-3 rounded-full font-bold text-white shadow-xl flex items-center gap-2 active:scale-95 transition-all border border-white/10 backdrop-blur-sm
                                    ${isRunningMap 
                                        ? 'bg-red-600/90 hover:bg-red-700' 
                                        : 'bg-indigo-600/90 hover:bg-indigo-700'}
                                `}
                            >
                                {isRunningMap ? (
                                    <>
                                        <Square size={18} fill="currentColor" />
                                        {t.stop}
                                    </>
                                ) : (
                                    <>
                                        <Play size={18} fill="currentColor" />
                                        {t.start}
                                    </>
                                )}
                            </button>
                        </div>
                    </div>

                    {/* Right/Bottom: List Area */}
                    <div className="flex-1 lg:w-[400px] xl:w-[450px] lg:flex-none bg-white dark:bg-slate-800 flex flex-col min-h-0 shadow-xl z-20 relative">
                        <div className="p-4 border-b border-slate-100 dark:border-slate-700 bg-slate-50/80 dark:bg-slate-900/50 shrink-0 flex justify-between items-center backdrop-blur-sm">
                             <div className="flex items-center gap-2">
                                <LayoutDashboard size={16} className="text-slate-400" />
                                <h3 className="font-bold text-xs uppercase text-slate-500 tracking-wider">Regional Nodes</h3>
                             </div>
                             <div className="text-xs text-slate-400 font-mono">
                                 {localizedRegions.length} nodes
                             </div>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 custom-scrollbar min-h-0 bg-slate-50/30 dark:bg-transparent">
                             {/* Responsive Grid: 1 col on mobile, 2 cols on wide list (tablet mode), back to 1 col on desktop sidebar, 2 cols on very wide desktop */}
                             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-1 xl:grid-cols-1 2xl:grid-cols-2 gap-3">
                                {LATENCY_REGIONS.map((region) => {
                                    const res = results[region.id];
                                    return (
                                        <div 
                                            key={region.id} 
                                            onClick={() => setSelectedRegion(region)}
                                            className="bg-white dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 flex justify-between items-center shadow-sm cursor-pointer hover:border-indigo-400 dark:hover:border-indigo-500 transition-all hover:shadow-md group"
                                        >
                                            <div className="flex flex-col min-w-0">
                                                <span className="font-bold text-slate-700 dark:text-slate-200 text-sm group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors truncate pr-2">
                                                    {getRegionName(region.id, region.name)}
                                                </span>
                                                <span className="text-[10px] text-slate-400 font-mono">{region.url.split('/')[2]}</span>
                                            </div>
                                            <div className="text-right flex items-center gap-3 shrink-0">
                                                {res ? (
                                                    res.status === 'pending' ? (
                                                        <Activity size={16} className="text-indigo-500 animate-pulse" />
                                                    ) : res.status === 'error' ? (
                                                        <span className="text-xs font-bold text-red-400 bg-red-50 dark:bg-red-900/20 px-2 py-0.5 rounded">{t.status_error}</span>
                                                    ) : (
                                                        <span className={`text-sm font-mono font-bold ${getLatencyColor(res.latency)}`}>
                                                            {res.latency} <span className="text-[10px] font-normal text-slate-400">ms</span>
                                                        </span>
                                                    )
                                                ) : (
                                                    <span className="text-xs text-slate-300 dark:text-slate-600">-</span>
                                                )}
                                            </div>
                                        </div>
                                    );
                                })}
                             </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    </Modal>
  );
};

import React, { useEffect, useRef, useState } from 'react';
import { Box, Play, Square, RefreshCw, Sliders, AlertTriangle, Maximize, Minimize } from 'lucide-react';
import { Translation } from '../utils/i18n/types';
import { Modal } from './ui/Modal';

// Fix for missing WebGPU types
type GPUCanvasContext = any /* eslint-disable-line @typescript-eslint/no-explicit-any */;
type GPUDevice = any /* eslint-disable-line @typescript-eslint/no-explicit-any */;
type GPUComputePipeline = any /* eslint-disable-line @typescript-eslint/no-explicit-any */;
type GPUBuffer = any /* eslint-disable-line @typescript-eslint/no-explicit-any */;
type _GPUBindGroup = any /* eslint-disable-line @typescript-eslint/no-explicit-any */;

interface RayTracingModalProps {
  onClose: () => void;
  t: Translation['rayTracing'];
}

// WGSL Shader Code
const SHADER_CODE = `
struct Ray {
    origin: vec3<f32>,
    direction: vec3<f32>,
}

struct Sphere {
    center: vec3<f32>,
    radius: f32,
    color: vec3<f32>,
    materialType: u32, // 0: Lambertian, 1: Metal, 2: Dielectric
    fuzz: f32, // For metal
}

struct Uniforms {
    resolution: vec2<f32>,
    time: f32,
    frame: u32,
    cameraPos: vec3<f32>,
    cameraTarget: vec3<f32>,
    roughness: f32,
    metalness: f32,
    baseColor: vec3<f32>,
}

@group(0) @binding(0) var outputTex: texture_storage_2d<rgba8unorm, write>;
@group(0) @binding(1) var<uniform> u: Uniforms;

// PCG Random Number Generator
fn rand(state: ptr<function, u32>) -> f32 {
    let oldState = *state;
    *state = oldState * 747796405u + 2891336453u;
    let word = ((*state >> ((*state >> 28u) + 4u)) ^ *state) * 277803737u;
    return f32((word >> 22u) ^ word) / 4294967296.0;
}

fn random_in_unit_sphere(state: ptr<function, u32>) -> vec3<f32> {
    var p: vec3<f32>;
    for (var i = 0; i < 10; i++) {
        p = 2.0 * vec3<f32>(rand(state), rand(state), rand(state)) - 1.0;
        if (length(p) < 1.0) { return p; }
    }
    return normalize(p); // Fallback
}

fn hit_sphere(center: vec3<f32>, radius: f32, r: Ray) -> f32 {
    let oc = r.origin - center;
    let a = dot(r.direction, r.direction);
    let b = 2.0 * dot(oc, r.direction);
    let c = dot(oc, oc) - radius * radius;
    let discriminant = b*b - 4.0*a*c;
    if (discriminant < 0.0) { return -1.0; }
    return (-b - sqrt(discriminant)) / (2.0*a);
}

@compute @workgroup_size(8, 8)
fn main(@builtin(global_invocation_id) id: vec3<u32>) {
    let width = u32(u.resolution.x);
    let height = u32(u.resolution.y);

    if (id.x >= width || id.y >= height) { return; }

    // Initialize RNG state based on pixel coord and frame
    var rngState = id.x + id.y * width + u.frame * 719393u;

    // Camera setup
    let uv = (vec2<f32>(id.xy) + vec2<f32>(rand(&rngState), rand(&rngState))) / u.resolution;
    let clip = uv * 2.0 - 1.0;
    // Fix aspect ratio
    let aspect = u.resolution.x / u.resolution.y;

    // LookAt Matrix construction (simplified)
    let w = normalize(u.cameraPos - u.cameraTarget);
    let up = vec3<f32>(0.0, 1.0, 0.0);
    let u_vec = normalize(cross(up, w));
    let v_vec = cross(w, u_vec);

    let viewportHeight = 2.0;
    let viewportWidth = aspect * viewportHeight;
    let horizontal = viewportWidth * u_vec;
    let vertical = viewportHeight * v_vec;
    let lowerLeftCorner = u.cameraPos - horizontal/2.0 - vertical/2.0 - w;

    let rayDir = normalize(lowerLeftCorner + uv.x * horizontal + (1.0 - uv.y) * vertical - u.cameraPos);

    var r = Ray(u.cameraPos, rayDir);
    var col = vec3<f32>(1.0);
    var accumulatedLight = vec3<f32>(0.0);

    // Dynamic Spheres
    var spheres = array<Sphere, 4>(
        Sphere(vec3<f32>(0.0, 0.0, -1.0), 0.5, u.baseColor, 1u, u.roughness), // Center (User controlled)
        Sphere(vec3<f32>(0.0, -100.5, -1.0), 100.0, vec3<f32>(0.2, 0.2, 0.2), 0u, 0.0), // Ground
        Sphere(vec3<f32>(1.0, 0.0, -1.0), 0.5, vec3<f32>(0.8, 0.6, 0.2), 1u, 0.0), // Right Metal
        Sphere(vec3<f32>(-1.0, 0.0, -1.0), 0.5, vec3<f32>(0.9, 0.9, 0.9), 2u, 0.0) // Left Glass
    );

    // Modify the center sphere based on metalness param (if > 0.5 switch to metal)
    if (u.metalness > 0.5) {
        spheres[0].materialType = 1u;
    } else {
        spheres[0].materialType = 0u;
    }

    // Bounce Loop
    for (var bounce = 0; bounce < 4; bounce++) {
        var hitT = 10000.0;
        var hitIndex = -1;

        for (var i = 0; i < 4; i++) {
            let t = hit_sphere(spheres[i].center, spheres[i].radius, r);
            if (t > 0.001 && t < hitT) {
                hitT = t;
                hitIndex = i;
            }
        }

        if (hitIndex != -1) {
            let p = r.origin + hitT * r.direction;
            let normal = normalize(p - spheres[hitIndex].center);
            let material = spheres[hitIndex].materialType;
            let attenuation = spheres[hitIndex].color;

            if (material == 0u) { // Lambertian
                let target = p + normal + random_in_unit_sphere(&rngState);
                r.origin = p;
                r.direction = normalize(target - p);
                col = col * attenuation;
            } else if (material == 1u) { // Metal
                let reflected = reflect(r.direction, normal);
                r.origin = p;
                r.direction = normalize(reflected + spheres[hitIndex].fuzz * random_in_unit_sphere(&rngState));
                col = col * attenuation;
            } else { // Dielectric
                let refraction_ratio = 1.5;
                // Simple refraction logic (always refract for demo speed)
                r.origin = p;
                r.direction = refract(r.direction, normal, 1.0/refraction_ratio);
                col = col * vec3<f32>(1.0); // No attenuation for glass usually
            }
        } else {
            // Sky color
            let unit_direction = normalize(r.direction);
            let t = 0.5 * (unit_direction.y + 1.0);
            let sky = (1.0 - t) * vec3<f32>(1.0, 1.0, 1.0) + t * vec3<f32>(0.5, 0.7, 1.0);
            accumulatedLight = col * sky;
            break; 
        }
    }

    // Writing to texture (no accumulation buffer in this simple version, just per-frame noise)
    // To implement true accumulation we need read-write textures or ping-pong buffers which adds complexity.
    // For a benchmark, raw rendering speed is enough, visual noise is expected in path tracing.
    textureStore(outputTex, id.xy, vec4<f32>(accumulatedLight, 1.0));
}
`;

export const RayTracingModal: React.FC<RayTracingModalProps> = ({ onClose, t }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [isRunning, setIsRunning] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [fps, setFps] = useState(0);
  const [spp, setSpp] = useState(0); // Actually Frame Count here since we don't accumulate
  const [isFullscreen, setIsFullscreen] = useState(false);

  useEffect(() => {
    const handleFullscreenChange = () => {
      setIsFullscreen(!!document.fullscreenElement);
    };
    document.addEventListener('fullscreenchange', handleFullscreenChange);
    return () => document.removeEventListener('fullscreenchange', handleFullscreenChange);
  }, []);

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      containerRef.current?.requestFullscreen().catch(err => {
         console.error(`Error attempting to enable fullscreen: ${err.message}`);
      });
    } else {
      if (document.exitFullscreen) {
        document.exitFullscreen();
      }
    }
  };

  // Scene Params
  const [roughness, setRoughness] = useState(0.5);
  const [metalness, setMetalness] = useState(0.0);
  const [color, setColor] = useState({ r: 0.8, g: 0.3, b: 0.3 });

  // WebGPU Refs
  const contextRef = useRef<GPUCanvasContext | null>(null);
  const deviceRef = useRef<GPUDevice | null>(null);
  const pipelineRef = useRef<GPUComputePipeline | null>(null);
  const uniformBufferRef = useRef<GPUBuffer | null>(null);
  const computeTextureRef = useRef<any /* eslint-disable-line @typescript-eslint/no-explicit-any */>(null);
  const rafRef = useRef<number | null>(null);
  const frameCountRef = useRef(0);
  const lastTimeRef = useRef(0);
  const isRunningRef = useRef(false);
  const isUnmountedRef = useRef(false);

  // Camera State
  const cameraAngleRef = useRef(0);
  const isDraggingRef = useRef(false);
  const lastMouseXRef = useRef(0);

  const initWebGPU = async () => {
    try {
      if (!(navigator as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).gpu) throw new Error("WebGPU not supported");
      const adapter = await (navigator as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).gpu.requestAdapter({ powerPreference: 'high-performance' });
      if (!adapter) throw new Error("No adapter found");
      const device = await adapter.requestDevice();
      deviceRef.current = device;

      const canvas = canvasRef.current;
      if (!canvas) return;
      const context = canvas.getContext('webgpu' as any /* eslint-disable-line @typescript-eslint/no-explicit-any */);
      if (!context) throw new Error("WebGPU context creation failed");
      contextRef.current = context;

      // GPUTextureUsage logic with fallback
      const TEXTURE_USAGE_STORAGE = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUTextureUsage?.STORAGE_BINDING || 0x08;
      const TEXTURE_USAGE_COPY_SRC = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUTextureUsage?.COPY_SRC || 0x01;
      const TEXTURE_USAGE_COPY_DST = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUTextureUsage?.COPY_DST || 0x02;
      const TEXTURE_USAGE_RENDER_ATTACHMENT = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUTextureUsage?.RENDER_ATTACHMENT || 0x10;

      // Force 'rgba8unorm' to match the storage texture and avoid bgra8unorm_storage requirement
      const format = 'rgba8unorm';
      (context as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).configure({
        device,
        format,
        alphaMode: 'premultiplied',
        usage: TEXTURE_USAGE_COPY_DST | TEXTURE_USAGE_RENDER_ATTACHMENT 
      });

      const computeTexture = device.createTexture({
        size: [canvas.width, canvas.height, 1],
        format: format,
        usage: TEXTURE_USAGE_STORAGE | TEXTURE_USAGE_COPY_SRC
      });
      computeTextureRef.current = computeTexture;

      const shaderModule = device.createShaderModule({ code: SHADER_CODE });

      const pipeline = device.createComputePipeline({
        layout: 'auto',
        compute: { module: shaderModule, entryPoint: 'main' }
      });
      pipelineRef.current = pipeline;

      // Uniform Buffer (size needs to be aligned to 16 bytes)
      // vec2 resolution (8) + time (4) + frame (4) + vec3 camPos (12+4pad) + vec3 camTarget (12+4pad) + rough (4) + metal (4) + vec3 color (12+4pad)
      // Total size: ~64 bytes is safe.
      const uniformBufferSize = 128; 
      // GPUBufferUsage logic with fallback
      const BUFFER_USAGE_UNIFORM = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUBufferUsage?.UNIFORM || 0x0040;
      const BUFFER_USAGE_COPY_DST = (window as any /* eslint-disable-line @typescript-eslint/no-explicit-any */).GPUBufferUsage?.COPY_DST || 0x0008;

      const uniformBuffer = device.createBuffer({
        size: uniformBufferSize,
        usage: BUFFER_USAGE_UNIFORM | BUFFER_USAGE_COPY_DST
      });
      uniformBufferRef.current = uniformBuffer;

      if (isUnmountedRef.current) {
         device.destroy();
         return;
      }

      startLoop();
    } catch (e: any /* eslint-disable-line @typescript-eslint/no-explicit-any */) {
      console.error(e);
      setError(t.error_webgpu || "WebGPU Error");
    }
  };

  const startLoop = () => {
    if (isRunningRef.current) return;
    isRunningRef.current = true;
    setIsRunning(true);
    frameCountRef.current = 0;

    const render = (time: number) => {
      if (!isRunningRef.current) return;
      if (!deviceRef.current || !pipelineRef.current || !contextRef.current || !uniformBufferRef.current || !computeTextureRef.current) return;

      // Stats
      if (time - lastTimeRef.current >= 1000) {
        setFps(Math.round(1000 / (time - lastTimeRef.current)));
        lastTimeRef.current = time;
      }
      frameCountRef.current++;
      setSpp(frameCountRef.current);

      // Camera Orbit
      const radius = 3.0;
      const camX = Math.sin(cameraAngleRef.current) * radius;
      const camZ = Math.cos(cameraAngleRef.current) * radius;

      // Update Uniforms
      const uniforms = new ArrayBuffer(128);
      const view = new DataView(uniforms);
      const canvas = canvasRef.current!;

      view.setFloat32(0, canvas.width, true);
      view.setFloat32(4, canvas.height, true);
      view.setFloat32(8, time / 1000, true);
      view.setUint32(12, frameCountRef.current, true);

      // Cam Pos
      view.setFloat32(16, camX, true);
      view.setFloat32(20, 1.0, true); // Height
      view.setFloat32(24, camZ, true);

      // Cam Target
      view.setFloat32(32, 0, true);
      view.setFloat32(36, 0, true);
      view.setFloat32(40, -1.0, true); // Look at center sphere

      // Material
      view.setFloat32(48, roughness, true);
      view.setFloat32(52, metalness, true);
      view.setFloat32(64, color.r, true);
      view.setFloat32(68, color.g, true);
      view.setFloat32(72, color.b, true);
      deviceRef.current.queue.writeBuffer(uniformBufferRef.current, 0, uniforms);

      // Create Bind Group (must be done per frame if texture view changes, which happens with canvas resize or swap chain)
      // We read from computeTexture which is static sizes, but conceptually neat to map it
      const bindGroup = deviceRef.current.createBindGroup({
        layout: pipelineRef.current.getBindGroupLayout(0),
        entries: [
          { binding: 0, resource: computeTextureRef.current.createView() },
          { binding: 1, resource: { buffer: uniformBufferRef.current } }
        ]
      });
      const commandEncoder = deviceRef.current.createCommandEncoder();
      const passEncoder = commandEncoder.beginComputePass();
      passEncoder.setPipeline(pipelineRef.current);
      passEncoder.setBindGroup(0, bindGroup);
      passEncoder.dispatchWorkgroups(Math.ceil(canvas.width / 8), Math.ceil(canvas.height / 8));
      passEncoder.end();

      commandEncoder.copyTextureToTexture(
          { texture: computeTextureRef.current },
          { texture: contextRef.current.getCurrentTexture() },
          [canvas.width, canvas.height, 1]
      );
      deviceRef.current.queue.submit([commandEncoder.finish()]);

      rafRef.current = requestAnimationFrame(render);
    };

    rafRef.current = requestAnimationFrame(render);
  };

  const stopLoop = () => {
    if (rafRef.current) {
        cancelAnimationFrame(rafRef.current);
        rafRef.current = null;
    }
    isRunningRef.current = false;
    setIsRunning(false);
  };

  useEffect(() => {
    isUnmountedRef.current = false;
    let localIsUnmounted = false;

    const init = async () => {
        await initWebGPU();
        if (localIsUnmounted) {
            stopLoop();
        }
    };
    init();

    return () => {
        isUnmountedRef.current = true;
        localIsUnmounted = true;
        stopLoop();
    };
  }, []);

  // Interaction Handlers
  const handleMouseDown = (e: React.MouseEvent) => {
      isDraggingRef.current = true;
      lastMouseXRef.current = e.clientX;
  };
  const handleMouseMove = (e: React.MouseEvent) => {
      if (!isDraggingRef.current) return;
      const delta = e.clientX - lastMouseXRef.current;
      cameraAngleRef.current += delta * 0.01;
      lastMouseXRef.current = e.clientX;
  };
  const handleMouseUp = () => {
      isDraggingRef.current = false;
  };

  const resetCamera = () => {
      cameraAngleRef.current = 0;
  };

  return (
    <Modal
        title={t.title}
        icon={<Box size={24} />}
        onClose={onClose}
        size="full"
        noPadding
    >
        <div ref={containerRef} className="flex flex-col h-full bg-black relative overflow-hidden group">

            {/* Fullscreen Toggle */}
            <button 
                onClick={toggleFullscreen}
                className="absolute top-4 right-4 z-50 p-2 bg-black/60 backdrop-blur-md border border-white/10 rounded-lg text-white hover:bg-white/20 transition-colors opacity-0 group-hover:opacity-100"
            >
                {isFullscreen ? <Minimize size={18} /> : <Maximize size={18} />}
            </button>

            {/* Main Canvas */}
            <canvas 
                ref={canvasRef}
                width={1280} 
                height={720}
                className="w-full h-full object-contain cursor-move touch-none"
                onMouseDown={handleMouseDown}
                onMouseMove={handleMouseMove}
                onMouseUp={handleMouseUp}
                onMouseLeave={handleMouseUp}
            />

            {/* Error Overlay */}
            {error && (
                <div className="absolute inset-0 flex items-center justify-center bg-slate-900/90 z-50">
                    <div className="p-6 bg-red-900/20 border border-red-500/50 rounded-xl text-center max-w-md">
                        <AlertTriangle size={48} className="mx-auto text-red-500 mb-4" />
                        <h3 className="text-xl font-bold text-white mb-2">WebGPU Error</h3>
                        <p className="text-red-200">{error}</p>
                    </div>
                </div>
            )}

            {/* Stats Overlay (Top Left) */}
            <div className="absolute top-4 left-4 z-20 flex gap-4 pointer-events-none">
                <div className="bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 text-xs font-mono">
                    <div className="text-slate-400 uppercase tracking-wider mb-1">{t.fps}</div>
                    <div className="text-2xl font-bold text-green-400">{fps}</div>
                </div>
                <div className="bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 text-xs font-mono">
                    <div className="text-slate-400 uppercase tracking-wider mb-1">{t.resolution}</div>
                    <div className="text-xl font-bold text-white">1280x720</div>
                </div>
                <div className="bg-black/60 backdrop-blur-md border border-white/10 rounded-lg p-3 text-xs font-mono">
                    <div className="text-slate-400 uppercase tracking-wider mb-1">Frame</div>
                    <div className="text-xl font-bold text-indigo-400">{spp}</div>
                </div>
            </div>

            {/* Controls Overlay (Bottom Center) */}
            <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-20 w-full max-w-2xl px-4 transition-transform duration-300 translate-y-0 opacity-100">
                <div className="bg-slate-900/80 backdrop-blur-xl border border-white/10 rounded-2xl p-6 shadow-2xl flex flex-col md:flex-row gap-6 items-center">

                    {/* Material Controls */}
                    <div className="flex-1 w-full space-y-4">
                        <div className="flex items-center justify-between text-xs text-slate-400 uppercase font-bold tracking-wider mb-2">
                            <span>{t.controls}</span>
                            <Sliders size={14} />
                        </div>

                        <div className="space-y-3">
                            <div className="flex items-center gap-3">
                                <span className="text-xs text-white w-16">{t.roughness}</span>
                                <input 
                                    type="range" min="0" max="1" step="0.01" 
                                    value={roughness} 
                                    onChange={(e) => setRoughness(parseFloat(e.target.value))}
                                    className="flex-1 h-1.5 bg-slate-700 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-indigo-500"
                                />
                            </div>
                            <div className="flex items-center gap-3">
                                <span className="text-xs text-white w-16">{t.metalness}</span>
                                <input 
                                    type="range" min="0" max="1" step="0.01" 
                                    value={metalness} 
                                    onChange={(e) => setMetalness(parseFloat(e.target.value))}
                                    className="flex-1 h-1.5 bg-slate-700 rounded-full appearance-none cursor-pointer [&::-webkit-slider-thumb]:appearance-none [&::-webkit-slider-thumb]:w-4 [&::-webkit-slider-thumb]:h-4 [&::-webkit-slider-thumb]:rounded-full [&::-webkit-slider-thumb]:bg-emerald-500"
                                />
                            </div>
                        </div>
                    </div>

                    <div className="w-px h-24 bg-white/10 hidden md:block" />

                    {/* Color & Actions */}
                    <div className="flex flex-col gap-4 items-center">
                        <div className="flex gap-2">
                            <button onClick={() => setColor({ r: 0.8, g: 0.3, b: 0.3 })} className="w-8 h-8 rounded-full bg-red-500 border-2 border-transparent hover:border-white transition-all ring-1 ring-black/50" />
                            <button onClick={() => setColor({ r: 0.3, g: 0.8, b: 0.3 })} className="w-8 h-8 rounded-full bg-green-500 border-2 border-transparent hover:border-white transition-all ring-1 ring-black/50" />
                            <button onClick={() => setColor({ r: 0.3, g: 0.3, b: 0.8 })} className="w-8 h-8 rounded-full bg-blue-500 border-2 border-transparent hover:border-white transition-all ring-1 ring-black/50" />
                            <button onClick={() => setColor({ r: 0.9, g: 0.9, b: 0.9 })} className="w-8 h-8 rounded-full bg-white border-2 border-transparent hover:border-white transition-all ring-1 ring-black/50" />
                        </div>

                        <div className="flex gap-3">
                            <button 
                                onClick={resetCamera}
                                className="px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-xs font-bold transition-colors flex items-center gap-2"
                            >
                                <RefreshCw size={14} /> {t.reset}
                            </button>
                            <button 
                                onClick={isRunning ? stopLoop : startLoop}
                                className={`px-6 py-2 rounded-lg text-xs font-bold transition-colors flex items-center gap-2 ${isRunning ? 'bg-red-600 hover:bg-red-500 text-white' : 'bg-green-600 hover:bg-green-500 text-white'}`}
                            >
                                {isRunning ? <Square size={14} fill="currentColor" /> : <Play size={14} fill="currentColor" />}
                                {isRunning ? t.stop : t.start}
                            </button>
                        </div>
                    </div>

                </div>
            </div>

        </div>
    </Modal>
  );
};

